// Combine data for Claude prompt
const user = $('Get Users with Digest Enabled').item.json;
const opportunities = $('Get Open Opportunities from People.ai').item.json;
const engagementChanges = $('Get Engagement Score Changes').item.json;

// Get assistant name (user override or org default)
const assistantName = user.assistant_name || user.org_default_assistant_name || 'Aria';

// Get assistant emoji (user override or org default)
const assistantEmoji = user.assistant_emoji || user.org_default_assistant_emoji || ':robot_face:';

// Format pipeline data for the prompt
const pipelineData = opportunities.data?.map(opp => {
  const engagement = engagementChanges.data?.find(e => e.opportunity_id === opp.id);
  return {
    account_name: opp.account_name,
    opportunity_name: opp.name,
    stage: opp.stage,
    close_date: opp.close_date,
    amount: opp.amount,
    engagement_score: opp.engagement_score,
    engagement_change: engagement?.change || 0,
    last_activity: opp.last_activity_date,
    days_in_stage: opp.days_in_current_stage,
    champion: opp.champion_name,
    champion_last_engagement: opp.champion_last_engagement_date,
    risks: opp.risk_signals || []
  };
}).sort((a, b) => {
  // Sort by urgency: engagement drops first, then by close date
  if (a.engagement_change < -10 && b.engagement_change >= -10) return -1;
  if (b.engagement_change < -10 && a.engagement_change >= -10) return 1;
  return new Date(a.close_date) - new Date(b.close_date);
});

return {
  user_id: user.id,
  slack_user_id: user.slack_user_id,
  rep_name: user.email.split('@')[0], // TODO: Get actual name
  assistant_name: assistantName,
  timezone: user.timezone || 'America/Los_Angeles',
  pipeline_data: JSON.stringify(pipelineData, null, 2),
  current_date: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
  assistant_emoji: assistantEmoji
};
